def safe_filename(text):
    return re.sub(r'[<>:"/\\|?*]', "_", text)

output_dir = Path("Characters")
output_dir.mkdir(exist_ok=True)
filename = output_dir / f"{safe_filename(char_culture)} - {safe_filename(char_class)} - {safe_filename(char_name)}.txt"
with filename.open("w", encoding="utf-8") as sys.stdout:
    print("Made with Drofseh's Pendragon 6E NPC Generator")
    print(version)
    print("")
    print("Name:", "", char_name, sep="\t")
    print("Gender:", "", char_gender, sep="\t")
    print("Born:", "", char_born, sep="\t")
    print("Homeland:", char_homeland, sep="\t")
    print("Lord:", "", char_lord, sep="\t")
    print("Class:", "", char_class, sep="\t")
    print("Culture:", char_culture, sep="\t")
    print("Religion:", char_religion, sep="\t")
    print("")
    print("Family Characteristics:")
    print("\t", ", ".join(char_familyCharacteristics), sep="")
    print("")
    print("Distinctive Features:")
    print("\t", char_features, sep="")
    print("")
    print("Characteristics:")
    print("\t", "SIZ", "\t", "DEX", "\t", "STR", "\t", "CON", "\t", "APP", sep='')
    print("\t", char_SIZ, "\t", char_DEX, "\t", char_STR, "\t", char_CON, "\t", char_APP, sep='')
    print("")
    print("Derived Characteristics:")
    print("\t", "Knockdown:", "\t", "\t", "\t", char_knockdown, sep='')
    print("\t", "Weapon Damage:", "\t", "\t", str(char_damage_weapon) + "d6" + char_damage_weapon_Bonus, sep='')
    print("\t", "Brawling Damage:", "\t", char_damage_brawling_Bonus + str(char_damage_brawling), sep='')
    print("\t", "Movement Rate:", "\t", "\t", char_movementRate, sep='')
    print("\t", "Major Wound:", "\t", "\t", char_woundMajor, sep='')
    print("\t", "Healing Rate:", "\t", "\t", char_healingRate, sep='')
    print("\t", "Total HP:", "\t", "\t", "\t", char_hitPointsTotal, sep='')
    print("\t", "Unconscious:", "\t", "\t", char_uncon, sep='')
    if len(char_ideal) > 0:
        print("")
        print("Ideal:")
        print(char_ideal)
    print("")
    print("Traits:")
    print("\t", "Chaste", "\t", "\t", char_traitChaste, "\t", "|", "\t", char_traitLustful, "\t", "Lustful", sep='')
    print("\t", "Energetic", "\t", char_traitEnergetic, "\t", "|", "\t", char_traitLazy, "\t", "Lazy", sep='')
    print("\t", "Forgiving", "\t", char_traitForgiving, "\t", "|", "\t", char_traitVengeful, "\t", "Vengeful", sep='')
    print("\t", "Generous", "\t", char_traitGenerous, "\t", "|", "\t", char_traitSelfish, "\t", "Selfish", sep='')
    print("\t", "Honest", "\t", "\t", char_traitHonest, "\t", "|", "\t", char_traitDeceitful, "\t", "Deceitful", sep='')
    print("\t", "Just", "\t", "\t", char_traitJust, "\t", "|", "\t", char_traitArbitrary, "\t", "Arbitrary", sep='')
    print("\t", "Merciful", "\t", char_traitMerciful, "\t", "|", "\t", char_traitCruel, "\t", "Cruel", sep='')
    print("\t", "Modest", "\t", "\t", char_traitModest, "\t", "|", "\t", char_traitProud, "\t", "Proud", sep='')
    print("\t", "Prudent", "\t", "\t", char_traitPrudent, "\t", "|", "\t", char_traitReckless, "\t", "Reckless", sep='')
    print("\t", "Spiritual", "\t", char_traitSpiritual, "\t", "|", "\t", char_traitWorldly, "\t", "Worldly", sep='')
    print("\t", "Temperate", "\t", char_traitTemperate, "\t", "|", "\t", char_traitIndulgent, "\t", "Indulgent", sep='')
    print("\t", "Trusting", "\t", char_traitTrusting, "\t", "|", "\t", char_traitSuspicious, "\t", "Suspicious", sep='')
    print("\t", "Valorous", "\t", char_traitValorous, "\t", "|", "\t", char_traitCowardly, "\t", "Cowardly", sep='')
    print("")
    print("Honor:", char_honor, sep="\t")
    print("")
    print("Passions:")
    for x in range(len(char_PassionsNames)):
        tempPassion = char_PassionsNames[x]
        tempLength = len(tempPassion) + 1
        padding = "\t"
        if tempLength < 20:
            padding = padding + "\t"
        if tempLength < 16:
            padding = padding + "\t"
        if tempLength < 12:
            padding = padding + "\t"
        if tempLength < 8:
            padding = padding + "\t"
        print("\t", tempPassion, ":", padding, char_PassionsValues[x], sep='')
    print("")
    print("Skills:")
    print("\tNon-Combat Skills:")
    for skill in Skills_NonCombat:
        print("\t\t", char_skills[skill], "\t", f"{skill}", sep="")

    print("\tCombat Skills:")
    for skill in Skills_Combat:
        print("\t\t", char_skills[skill], "\t", f"{skill}", sep="")
